// Process calendar events
const events = $input.item(0).json || [];

// Categorize by time blocks
const morning = [];
const afternoon = [];
const evening = [];

events.forEach(event => {
  const startTime = new Date(event.start.dateTime || event.start.date);
  const hour = startTime.getHours();

  const eventItem = {
    time: startTime.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }),
    title: event.summary,
    location: event.location || '',
    link: event.htmlLink
  };

  if (hour < 12) morning.push(eventItem);
  else if (hour < 17) afternoon.push(eventItem);
  else evening.push(eventItem);
});

return {
  totalEvents: events.length,
  morning,
  afternoon,
  evening
};

// Process tasks
const tasks = $input.item(0).json || [];

// Categorize by project and priority
const byProject = {};
const highPriority = [];

tasks.forEach(task => {
  const project = task.project_id || 'Inbox';

  if (!byProject[project]) {
    byProject[project] = [];
  }

  const taskItem = {
    content: task.content,
    priority: task.priority,
    due: task.due ? task.due.date : 'No due date',
    url: task.url,
    labels: task.labels || []
  };

  byProject[project].push(taskItem);

  if (task.priority >= 3) {
    highPriority.push(taskItem);
  }
});

return {
  totalTasks: tasks.length,
  byProject,
  highPriority
};

// Get all data
const calendar = $input.item(0).json;
const tasks = $input.item(1).json;
const inboxCount = parseInt($input.item(2).json.stdout.trim());
const yesterdayNotes = parseInt($input.item(3).json.stdout.trim());

const today = new Date();
const dateStr = today.toISOString().split('T')[0]; // YYYY-MM-DD
const dayName = today.toLocaleDateString('en-US', { weekday: 'long' });

// Create daily note content in Obsidian format
const noteContent = `---
date: ${dateStr}
day: ${dayName}
tags: [daily-note, ${today.getFullYear()}, ${today.toLocaleDateString('en-US', { month: 'long' }).toLowerCase()}]
inbox_count: ${inboxCount}
events: ${calendar.totalEvents}
tasks: ${tasks.totalTasks}
---

# ${dayName}, ${today.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}

## 🎯 Today's Focus

<!-- What are your top 3 priorities for today? -->

1. 
2. 
3. 

---

## 📅 Schedule

${calendar.totalEvents === 0 ? '_No events scheduled today_' : ''}

${calendar.morning.length > 0 ? `### 🌅 Morning\n${calendar.morning.map(e => `- **${e.time}** - ${e.title}${e.location ? ` @ ${e.location}` : ''}`).join('\n')}\n` : ''}

${calendar.afternoon.length > 0 ? `### ☀️ Afternoon\n${calendar.afternoon.map(e => `- **${e.time}** - ${e.title}${e.location ? ` @ ${e.location}` : ''}`).join('\n')}\n` : ''}

${calendar.evening.length > 0 ? `### 🌙 Evening\n${calendar.evening.map(e => `- **${e.time}** - ${e.title}${e.location ? ` @ ${e.location}` : ''}`).join('\n')}\n` : ''}

---

## ✅ Tasks (${tasks.totalTasks})

${tasks.highPriority.length > 0 ? `### 🔴 High Priority\n${tasks.highPriority.map(t => `- [ ] ${t.content}`).join('\n')}\n` : ''}

${Object.entries(tasks.byProject).map(([project, projectTasks]) => 
  `### ${project} (${projectTasks.length})\n${projectTasks.map(t => `- [ ] ${t.content}${t.labels.length > 0 ? ` #${t.labels.join(' #')}` : ''}`).join('\n')}`
).join('\n\n')}

---

## 📝 Notes

<!-- Capture thoughts, insights, and observations throughout the day -->



---

## 🧠 Knowledge Work

### 💡 Ideas



### 📚 Learned Today



### 🔗 Connections Made

<!-- Link to related notes -->



---

## 📊 Daily Stats

- **📥 Inbox Items:** ${inboxCount} ${inboxCount > 10 ? '⚠️ _Time to process!_' : ''}
- **📝 Notes Created Yesterday:** ${yesterdayNotes}
- **📅 Events Today:** ${calendar.totalEvents}
- **✅ Tasks Due:** ${tasks.totalTasks}

---

## 🔄 Daily Review (End of Day)

### What went well?



### What could be improved?



### Tomorrow's preparation



---

## 📎 Quick Links

- [[Weekly Review]]
- [[Monthly Goals]]
- [[Active Projects]]
- [[Inbox]]

---

_Created automatically on ${today.toLocaleString()}_
`;

const filename = `${dateStr}-daily.md`;
const vaultPath = '~/Library/Mobile Documents/iCloud~md~obsidian/Documents/MyVault';

return {
  noteContent,
  filename,
  vaultPath,
  dateStr,
  stats: {
    inboxCount,
    yesterdayNotes,
    eventsToday: calendar.totalEvents,
    tasksToday: tasks.totalTasks
  }
};
